import mysql.connector

def import_data(file_path, table_name):
    # Connect to MySQL database
    config = {
        'user': 'your_username',
        'password': 'your_password',
        'host': 'localhost',
        'database': 'your_database',
        'raise_on_warnings': True,
        'local_infile': True  # Enable local infile
    }
    
    try:
        cnx = mysql.connector.connect(**config)
        cursor = cnx.cursor()
        
        # Construct the LOAD DATA INFILE statement
        query = "LOAD DATA INFILE '{}' INTO TABLE {}".format(file_path, table_name)
        
        # Execute the query
        cursor.execute(query)
        
        print("Data imported successfully.")
    
    except mysql.connector.Error as err:
        print(f"Error: {err}")
    
    finally:
        if cnx.is_connected():
            cursor.close()
            cnx.close()

# Example usage
if __name__ == "__main__":
    file_path = input("Enter the file path to import: ")
    table_name = input("Enter the table name to import into: ")
    import_data(file_path, table_name)